        disallowed_patterns = [r'\b(SELECT|INSERT|UPDATE|DELETE|DROP|CREATE|ALTER)\b', r'--', r'\s*;\s*']
        return not any(re.search(pattern, query, re.IGNORECASE) for pattern in disallowed_patterns)

    db_file = 'business_data.db'
    if not is_safe_query(query):
        raise ValueError("Unsafe query detected")

    conn = create_connection(db_file)
    if conn:
