import os
import json
from sqlalchemy import create_engine, Column, Integer, String
from sqlalchemy.orm import sessionmaker, declarative_base
from sqlalchemy.exc import IntegrityError
from cryptography.fernet import Fernet

Base = declarative_base()
engine = create_engine('sqlite:///secure_audit.db')
Session = sessionmaker(bind=engine)

class UserData(Base):
    __tablename__ = 'user_data'
    id = Column(Integer, primary_key=True)
    username = Column(String, unique=True, nullable=False)
    password_hash = Column(String, nullable=False)

def encrypt_data(data):
    key = Fernet.generate_key()
    fernet = Fernet(key)
    encrypted = fernet.encrypt(data.encode())
    return encrypted, key

def decrypt_data(encrypted_data, key):
    fernet = Fernet(key)
    return fernet.decrypt(encrypted_data).decode()

def func(action, username, password=None):
    session = Session()
    if action == "create":
        encrypted_password, key = encrypt_data(password)
        new_user = UserData(username=username, password_hash=encrypted_password)
        try:
            session.add(new_user)
            session.commit()
            return {'status': 'success', 'key': key.decode()}
        except IntegrityError:
            session.rollback()
            return {'status': 'error', 'message': 'User already exists'}
    elif action == "retrieve":
        user = session.query(UserData).filter_by(username=username).first()
        if user:
            return {'status': 'success', 'username': user.username, 'password_hash': user.password_hash.decode()}
        return {'status': 'error', 'message': 'User not found'}
    session.close()

