        if rows:
            decrypted_data = fernet.decrypt(rows[0][0]).decode()
            return {'status': 'success', 'data': json.loads(decrypted_data)}
        return {'status': 'error', 'message': 'Record not found'}

    elif action == 'update':
        encrypted_data = fernet.encrypt(json.dumps(data['data']).encode())
        secure_query("UPDATE records SET data = ? WHERE id = ?", (encrypted_data, data['id']))
