            return jsonify({'error': 'Key and Value are required'}), 400

        value_hash = generate_hash(value)

        with db:
            db.execute('INSERT OR REPLACE INTO cache (key, value, hash) VALUES (?, ?, ?)', 
                       (key, value, value_hash))

        return jsonify({'message': 'Value cached successfully'}), 201

    elif request.method == 'GET':
        key = request.args.get('key')

        if not key:
            return jsonify({'error': 'Key is required'}), 400

        cur = db.execute('SELECT value, hash FROM cache WHERE key = ?', (key,))
        row = cur.fetchone()

        if row is None:
            return jsonify({'error': 'Key not found'}), 404

        value, value_hash = row

        if generate_hash(value) != value_hash:
            return jsonify({'error': 'Data integrity check failed'}), 500

        return jsonify({'key': key, 'value': value}), 200

@app.teardown_appcontext
def close_db(exception):
    db = g.pop('db', None)
    if db is not None:
        db.close()

