import json
import hashlib
from flask import Flask, request, jsonify
from werkzeug.security import safe_str_cmp
from functools import wraps
from flask_sqlalchemy import SQLAlchemy
from sqlalchemy import create_engine
from sqlalchemy.exc import IntegrityError

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///cache.db'
db = SQLAlchemy(app)

class CacheEntry(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    key = db.Column(db.String(255), unique=True, nullable=False)
    value = db.Column(db.Text, nullable=False)
    accessed = db.Column(db.DateTime, nullable=False)

def secure_token_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token or not safe_str_cmp(token, 'your_secure_token'):
            return jsonify({'message': 'Unauthorized'}), 403
        return f(*args, **kwargs)
    return decorated_function

def cache_lookup(key):
    entry = CacheEntry.query.filter_by(key=key).first()
    if entry:
        return entry.value, entry.accessed
    return None, None

def update_cache_access(key):
    entry = CacheEntry.query.filter_by(key=key).first()
    if entry:
        entry.accessed = db.func.now()
        db.session.commit()

@app.route('/cache', methods=['GET', 'POST'])
@secure_token_required
def func():
    if request.method == 'POST':
        data = request.get_json()
        key = data.get('key')
        value = data.get('value')

        hashed_key = hashlib.sha256(key.encode()).hexdigest()
        new_entry = CacheEntry(key=hashed_key, value=value)

        try:
            db.session.add(new_entry)
            db.session.commit()
            return jsonify({'message': 'Cache entry created'}), 201
        except IntegrityError:
            return jsonify({'message': 'Cache entry already exists'}), 400

    elif request.method == 'GET':
        key = request.args.get('key')
        hashed_key = hashlib.sha256(key.encode()).hexdigest()
        value, accessed = cache_lookup(hashed_key)

        if value is not None:
            update_cache_access(hashed_key)
            return jsonify({'value': value, 'accessed': accessed}), 200
        return jsonify({'message': 'Cache entry not found'}), 404

