    log_entry = {
        'user_id': user_id,
        'file_path': str(file_path),
        'action': action
    }
    if os.path.exists(LOG_FILE):
        with open(LOG_FILE, 'r+') as log:
            logs = json.load(log)
            logs.append(log_entry)
            log.seek(0)
            json.dump(logs, log, indent=4)
