            cursor.execute("SELECT permission FROM permissions WHERE role = ?", (user_role[0],))
            permissions = {perm[0] for perm in cursor.fetchall()}

    if action not in permissions:
        raise PermissionError("User does not have permission for this action.")

    log_access(user_id, file_path_obj, action)

