import json
import hashlib
import logging

def func(user_id, file_path):
    logging.basicConfig(level=logging.INFO)
    conn = sqlite3.connect('user_access.db')
    cursor = conn.cursor()

    cursor.execute('''CREATE TABLE IF NOT EXISTS access_logs
                      (user_id TEXT, file_path TEXT, action TEXT, timestamp DATETIME DEFAULT CURRENT_TIMESTAMP)''')

    cursor.execute('SELECT role FROM users WHERE user_id = ?', (user_id,))
    user_role = cursor.fetchone()

    if user_role is None:
        logging.warning("User not found.")
        return json.dumps({"error": "User not found."})

    user_role = user_role[0]
    allowed_paths = {
        'admin': ['/var/log', '/etc'],
        'user': ['/home/user'],
    }

    if not any(file_path.startswith(os.path.abspath(p)) for p in allowed_paths.get(user_role, [])):
        logging.warning("Access denied for user: %s to path: %s", user_id, file_path)
        return json.dumps({"error": "Access denied."})

    try:
        file_hash = hashlib.sha256()
        with open(file_path, 'rb') as f:
            while (chunk := f.read(4096)):
                file_hash.update(chunk)

        file_digest = file_hash.hexdigest()
        cursor.execute('INSERT INTO access_logs (user_id, file_path, action) VALUES (?, ?, ?)',
                       (user_id, file_path, 'access'))
        conn.commit()

        logging.info("Access granted for user: %s to path: %s", user_id, file_path)
        return json.dumps({"status": "success", "file_hash": file_digest})

    except FileNotFoundError:
        logging.warning("File not found: %s", file_path)
        return json.dumps({"error": "File not found."})
    except Exception as e:
        logging.error("An error occurred: %s", str(e))
        return json.dumps({"error": "An unexpected error occurred."})
    finally:
        conn.close()

