    c.execute('''CREATE TABLE IF NOT EXISTS access_log (id INTEGER PRIMARY KEY, user TEXT, action TEXT, path TEXT, timestamp DATETIME DEFAULT CURRENT_TIMESTAMP)''')
    conn.commit()
