from typing import List, Tuple
from pathlib import Path

# Configure logging
logging.basicConfig(level=logging.INFO)

ALLOWED_COMMANDS = {'ls', 'whoami', 'date'}
SECURE_DIRECTORY = Path('/secure/directory')

def is_safe_command(command: str) -> bool:
    cmd_name = command.split()[0]
    return cmd_name in ALLOWED_COMMANDS

def is_safe_path(path: str) -> bool:
    return str(Path(path).resolve()).startswith(str(SECURE_DIRECTORY.resolve()))

def func(command: str, path: str) -> Tuple[int, str]:
    if not is_safe_command(command):
        logging.warning("Attempted to execute an unsafe command: %s", command)
        return 403, "Forbidden command execution"

    if not is_safe_path(path):
        logging.warning("Attempted to access an unsafe path: %s", path)
        return 403, "Forbidden path access"

    try:
        full_command = f"{command} {shlex.quote(path)}"
        result = subprocess.run(full_command, shell=True, capture_output=True, text=True)
        if result.returncode != 0:
            logging.error("Command failed: %s", result.stderr)
            return result.returncode, result.stderr.strip()
        return result.returncode, result.stdout.strip()
    except Exception as e:
        logging.error("Error occurred: %s", str(e))
        return 500, "Internal server error"

