from contextlib import closing
from cryptography.fernet import Fernet

def func(service_id, user_id, action):
    def get_service_credentials(service_id):
        with closing(psycopg2.connect(dbname='services_db', user='user', password='pass', host='localhost')) as conn:
            with conn.cursor() as cursor:
                cursor.execute("SELECT api_key, secret FROM services WHERE id = %s", (service_id,))
                return cursor.fetchone()

    def log_rpc_call(user_id, service_id, action):
        logging.basicConfig(filename='rpc_calls.log', level=logging.INFO)
        logging.info(f'User {user_id} called action {action} on service {service_id}')

    def decrypt_credentials(encrypted_key):
        fernet = Fernet(os.environ.get("FERNET_KEY").encode())
        return fernet.decrypt(encrypted_key).decode()

    service_credentials = get_service_credentials(service_id)
    if not service_credentials:
        raise ValueError("Service not found")

    api_key, encrypted_secret = service_credentials
    secret = decrypt_credentials(encrypted_secret)

    log_rpc_call(user_id, service_id, action)

    response = {
        "api_key": api_key,
        "secret": secret,
        "action": action,
        "status": "success"
    }

    return json.dumps(response)

