import hashlib
import secrets
from typing import Any, Dict
import sqlite3
from contextlib import closing

SECRET_KEY = secrets.token_bytes(32)

def generate_signature(data: str) -> str:
    return hmac.new(SECRET_KEY, data.encode(), hashlib.sha256).hexdigest()

def verify_signature(data: str, signature: str) -> bool:
    expected_signature = generate_signature(data)
    return hmac.compare_digest(expected_signature, signature)

def fetch_user_data(user_id: str) -> Dict[str, Any]:
    with closing(sqlite3.connect('database.db')) as conn:
        cursor = conn.cursor()
        cursor.execute("SELECT * FROM users WHERE user_id = ?", (user_id,))
        result = cursor.fetchone()
        if result:
            return {'user_id': result[0], 'name': result[1], 'email': result[2]}
        return {}

def func(request: str) -> str:
    request_data = json.loads(request)
    user_id = request_data.get('user_id')
    signature = request_data.get('signature')

    if not user_id or not signature:
        return json.dumps({"error": "Invalid request"}), 400

    if not verify_signature(request, signature):
        return json.dumps({"error": "Invalid signature"}), 403

    user_data = fetch_user_data(user_id)

    if not user_data:
        return json.dumps({"error": "User not found"}), 404

    return json.dumps(user_data), 200

