import json
import hmac
import hashlib
import secrets
from datetime import datetime, timedelta
import sqlite3

DATABASE = 'service_audit.db'
SECRET_KEY = b'supersecretkey'

def create_audit_log(service_name, action, user_id):
    conn = sqlite3.connect(DATABASE)
    cursor = conn.cursor()
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS audit_log (
            id INTEGER PRIMARY KEY,
            timestamp TEXT,
            service_name TEXT,
            action TEXT,
            user_id TEXT,
            signature TEXT
        )
    ''')
    timestamp = datetime.utcnow().isoformat()
    audit_data = f"{timestamp}:{service_name}:{action}:{user_id}"
    signature = hmac.new(SECRET_KEY, audit_data.encode(), hashlib.sha256).hexdigest()
    cursor.execute('INSERT INTO audit_log (timestamp, service_name, action, user_id, signature) VALUES (?, ?, ?, ?, ?)',
                   (timestamp, service_name, action, user_id, signature))
    conn.commit()
    conn.close()

def func(service_name, action, user_id):
    if not isinstance(service_name, str) or not isinstance(action, str) or not isinstance(user_id, str):
        raise ValueError("Invalid input types")

    create_audit_log(service_name, action, user_id)

    if action == "start":
        return json.dumps({"status": "success", "message": f"{service_name} has been started for user {user_id}."})
    elif action == "stop":
        return json.dumps({"status": "success", "message": f"{service_name} has been stopped for user {user_id}."})
    elif action == "status":
        return json.dumps({"status": "success", "message": f"Fetching status for {service_name} for user {user_id}."})
    else:
        return json.dumps({"status": "error", "message": "Invalid action."})

