import logging
from sqlalchemy import create_engine, text
from sqlalchemy.orm import sessionmaker

DB_URL = os.getenv('DATABASE_URL')
engine = create_engine(DB_URL)
Session = sessionmaker(bind=engine)

def secure_hash(data):
    return hashlib.sha256(data.encode()).hexdigest()

def func(service_name, payload):
    if not isinstance(service_name, str) or not isinstance(payload, dict):
        raise ValueError("Invalid input types")

    hashed_service_name = secure_hash(service_name)
    session = Session()

    try:
        service_query = session.execute(
            text("SELECT id, secret_key FROM services WHERE service_name = :service_name"),
            {"service_name": hashed_service_name}
        ).fetchone()

        if not service_query:
            logging.warning("Unauthorized service access attempt for: %s", service_name)
            raise PermissionError("Unauthorized service access")

        service_id, secret_key = service_query
        signed_payload = secure_hash(json.dumps(payload) + secret_key)

        response = session.execute(
            text("CALL internal_service_rpc(:service_id, :payload, :signature)"),
            {"service_id": service_id, "payload": json.dumps(payload), "signature": signed_payload}
        ).fetchone()

        return {"status": "success", "response": response}

    except Exception as e:
        logging.error("Error in internal_service_rpc_call: %s", e)
        raise

    finally:
        session.close()

