from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)
db_path = 'database.db'
logging.basicConfig(level=logging.INFO)

def secure_rpc_call_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token or token != os.environ.get('SECURE_TOKEN'):
            logging.warning("Unauthorized access attempt.")
            return jsonify({"error": "Unauthorized"}), 401
        return f(*args, **kwargs)
    return decorated_function

def db_connection():
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    return conn

@app.route('/rpc/<service_name>', methods=['POST'])
@secure_rpc_call_required
def func(service_name):
    data = request.get_json()
    user_id = data.get('user_id')
    action = data.get('action')

    if not user_id or not action:
        return jsonify({"error": "Invalid input"}), 400

    conn = db_connection()
    try:
        cursor = conn.cursor()

        cursor.execute("SELECT * FROM services WHERE name = ?", (service_name,))
        service = cursor.fetchone()

        if not service:
            return jsonify({"error": "Service not found"}), 404

        if action not in service['allowed_actions'].split(','):
            return jsonify({"error": "Action not permitted"}), 403

        cursor.execute("INSERT INTO service_logs (user_id, service_name, action) VALUES (?, ?, ?)",
                       (user_id, service_name, action))
        conn.commit()

        result = {"status": "success", "message": f"Action {action} performed on {service_name}"}
        return jsonify(result), 200

    except Exception as e:
        logging.error(f"Error during RPC call: {str(e)}")
        return jsonify({"error": "Internal server error"}), 500

    finally:
        conn.close()

if __name__ == "__main__":
