from cryptography.fernet import Fernet
from datetime import datetime

class SecureTransactionHandler:
    def __init__(self, db_path, encryption_key):
        self.connection = sqlite3.connect(db_path)
        self.cursor = self.connection.cursor()
        self.fernet = Fernet(encryption_key)

    def create_tables(self):
        self.cursor.execute('''CREATE TABLE IF NOT EXISTS transactions (
                                id INTEGER PRIMARY KEY AUTOINCREMENT,
                                amount REAL NOT NULL,
                                description TEXT NOT NULL,
                                timestamp TEXT NOT NULL,
                                user_id INTEGER NOT NULL,
                                FOREIGN KEY (user_id) REFERENCES users (id)
                              )''')
        self.connection.commit()

    def log_transaction(self, amount, description, user_id):
        if amount <= 0:
            raise ValueError("Transaction amount must be positive.")
        timestamp = datetime.utcnow().isoformat()
        self.cursor.execute('''INSERT INTO transactions (amount, description, timestamp, user_id)
                               VALUES (?, ?, ?, ?)''', (amount, description, timestamp, user_id))
        self.connection.commit()

    def get_transaction_history(self, user_id):
        self.cursor.execute('''SELECT id, amount, description, timestamp FROM transactions
                               WHERE user_id = ? ORDER BY timestamp DESC''', (user_id,))
        return self.cursor.fetchall()

    def encrypt_data(self, data):
        return self.fernet.encrypt(data.encode()).decode()

    def decrypt_data(self, encrypted_data):
        return self.fernet.decrypt(encrypted_data.encode()).decode()

    def close(self):
        self.connection.close()

def func(db_path, encryption_key, user_id, amount, description):
    handler = SecureTransactionHandler(db_path, encryption_key)
    handler.create_tables()
    handler.log_transaction(amount, description, user_id)
    transactions = handler.get_transaction_history(user_id)
    handler.close()
    return transactions

