from cryptography.hazmat.primitives import serialization
from cryptography.hazmat.backends import default_backend
from cryptography.hazmat.primitives.asymmetric import rsa
from cryptography.exceptions import InvalidSignature

def func(action, key_id=None, data=None):
    conn = sqlite3.connect('keys_db.sqlite')
    cursor = conn.cursor()

    if action == 'generate_key':
        private_key = rsa.generate_private_key(public_exponent=65537, key_size=2048, backend=default_backend())
        public_key = private_key.public_key()
        private_pem = private_key.private_bytes(encoding=serialization.Encoding.PEM, format=serialization.PrivateFormat.TraditionalOpenSSL)
        public_pem = public_key.public_bytes(encoding=serialization.Encoding.PEM, format=serialization.PublicFormat.SubjectPublicKeyInfo)
        cursor.execute("INSERT INTO keys (public_key, private_key) VALUES (?, ?)", (public_pem, private_pem))
        conn.commit()
        return {'status': 'key_generated', 'public_key': public_pem.decode(), 'private_key': private_pem.decode()}

    elif action == 'sign_data':
        cursor.execute("SELECT private_key FROM keys WHERE id=?", (key_id,))
        row = cursor.fetchone()
        if row:
            private_key = serialization.load_pem_private_key(row[0], password=None, backend=default_backend())
            signature = private_key.sign(data.encode(), padding=serialization.PKCS1v15(), algorithm=hashlib.sha256())
            return {'status': 'data_signed', 'signature': signature.hex()}
        else:
            return {'status': 'error', 'message': 'Key not found'}

    elif action == 'verify_signature':
        cursor.execute("SELECT public_key FROM keys WHERE id=?", (key_id,))
        row = cursor.fetchone()
        if row:
            public_key = serialization.load_pem_public_key(row[0], backend=default_backend())
            try:
                public_key.verify(bytes.fromhex(data['signature']), data['message'].encode(), signature=serialization.PKCS1v15(), algorithm=hashlib.sha256())
                return {'status': 'signature_valid'}
            except InvalidSignature:
                return {'status': 'signature_invalid'}
        else:
            return {'status': 'error', 'message': 'Key not found'}

    conn.close()

