    close_db()

def verify_signature(data, signature):
    return hmac.compare_digest(hmac.new(SECRET_KEY.encode(), data.encode(), hashlib.sha256).hexdigest(), signature)

def secure_audit(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        data = request.json
        if not data or not verify_signature(data.get('payload'), data.get('signature')):
            return jsonify({'error': 'Unauthorized access'}), 403
        return func(*args, **kwargs)
    return wrapper

