from datetime import datetime

def func(action, key=None, data=None, user_id=None):
    if action not in ['encrypt', 'decrypt', 'generate_key']:
        raise ValueError("Invalid action. Use 'encrypt', 'decrypt', or 'generate_key'.")

    conn = sqlite3.connect('secure_audit.db')
    cursor = conn.cursor()

    if action == 'generate_key':
        key = Fernet.generate_key()
        cursor.execute("INSERT INTO keys (user_id, key, created_at) VALUES (?, ?, ?)", 
                       (user_id, key.decode(), datetime.now()))
        conn.commit()
        return key.decode()

    if action == 'encrypt':
        if not key or not data:
            raise ValueError("Key and data are required for encryption.")
        try:
            fernet = Fernet(key.encode())
            encrypted_data = fernet.encrypt(data.encode())
            cursor.execute("INSERT INTO audits (user_id, action, timestamp, data) VALUES (?, ?, ?, ?)", 
                           (user_id, 'encrypt', datetime.now(), encrypted_data.decode()))
            conn.commit()
            return encrypted_data.decode()
        except Exception as e:
            raise ValueError(f"Encryption failed: {str(e)}")

    if action == 'decrypt':
        if not key or not data:
            raise ValueError("Key and data are required for decryption.")
        try:
            fernet = Fernet(key.encode())
            decrypted_data = fernet.decrypt(data.encode())
            cursor.execute("INSERT INTO audits (user_id, action, timestamp, data) VALUES (?, ?, ?, ?)", 
                           (user_id, 'decrypt', datetime.now(), decrypted_data.decode()))
            conn.commit()
            return decrypted_data.decode()
        except Exception as e:
            raise ValueError(f"Decryption failed: {str(e)}")

    conn.close()

