import sqlite3

def func(action, key_id, data=None):
    conn = sqlite3.connect('secure_storage.db')
    cursor = conn.cursor()
    cursor.execute("CREATE TABLE IF NOT EXISTS keys (id TEXT PRIMARY KEY, secret TEXT)")

    if action == 'store_key':
        if not data or 'secret' not in data:
            return {'error': 'Missing secret data'}
        key_secret = base64.b64encode(data['secret'].encode()).decode()
        cursor.execute("INSERT OR REPLACE INTO keys (id, secret) VALUES (?, ?)", (key_id, key_secret))
        conn.commit()
        return {'status': 'key stored'}

    elif action == 'retrieve_key':
        cursor.execute("SELECT secret FROM keys WHERE id=?", (key_id,))
        row = cursor.fetchone()
        if row:
            return {'secret': base64.b64decode(row[0]).decode()}
        return {'error': 'Key not found'}

    elif action == 'generate_hmac':
        cursor.execute("SELECT secret FROM keys WHERE id=?", (key_id,))
        row = cursor.fetchone()
        if row:
            secret = base64.b64decode(row[0])
            hmac_result = hmac.new(secret, data.encode(), hashlib.sha256).hexdigest()
            return {'hmac': hmac_result}
        return {'error': 'Key not found'}

    conn.close()

