import sqlite3

def func(operation, data, key):
    if operation not in ['encrypt', 'decrypt', 'hash', 'verify']:
        raise ValueError("Invalid operation specified.")

    conn = sqlite3.connect('secure_storage.db')
    cursor = conn.cursor()

    cursor.execute('CREATE TABLE IF NOT EXISTS secure_keys (id INTEGER PRIMARY KEY, key BLOB)')
    cursor.execute('SELECT key FROM secure_keys WHERE id = 1')
    stored_key = cursor.fetchone()

    if stored_key:
        stored_key = stored_key[0]
    else:
        cursor.execute('INSERT INTO secure_keys (key) VALUES (?)', (key,))
        conn.commit()
        stored_key = key

    if operation == 'encrypt':
        encrypted_data = hmac.new(stored_key, data.encode(), hashlib.sha256).hexdigest()
        return encrypted_data

    elif operation == 'decrypt':
        raise NotImplementedError("Decryption logic not implemented for security reasons.")

    elif operation == 'hash':
        return hashlib.sha256(data.encode()).hexdigest()

    elif operation == 'verify':
        if len(data.split(',')) != 2:
            raise ValueError("Data must contain the hash and original data for verification.")
        data_hash, original_data = data.split(',')
        verification_result = hmac.compare_digest(data_hash, hmac.new(stored_key, original_data.encode(), hashlib.sha256).hexdigest())
        return verification_result

    conn.close()

import os
