import base64
import json
from cryptography.fernet import Fernet
from sqlalchemy import create_engine, Table, MetaData, select

def func(operation, key=None, data=None, db_url='sqlite:///secure_db.sqlite'):
    engine = create_engine(db_url)
    metadata = MetaData(bind=engine)
    secure_data_table = Table('secure_data', metadata, autoload_with=engine)

    if operation == 'generate_key':
        key = Fernet.generate_key()
        return base64.urlsafe_b64encode(key).decode()

    if operation == 'encrypt':
        if not key or not data:
            raise ValueError("Key and data are required for encryption")
        fernet = Fernet(key)
        encrypted_data = fernet.encrypt(data.encode())
        with engine.connect() as connection:
            connection.execute(secure_data_table.insert().values(encrypted_data=encrypted_data))
        return encrypted_data.decode()

    if operation == 'decrypt':
        if not key or not data:
            raise ValueError("Key and data are required for decryption")
        fernet = Fernet(key)
        decrypted_data = fernet.decrypt(data.encode())
        return decrypted_data.decode()

    if operation == 'verify_integrity':
        if not key or not data:
            raise ValueError("Key and data are required for integrity check")
        hash_data = hmac.new(key.encode(), data.encode(), hashlib.sha256).hexdigest()
        return hash_data

    if operation == 'retrieve':
        with engine.connect() as connection:
            result = connection.execute(select([secure_data_table])).fetchall()
        return [json.loads(row[1]) for row in result]

    raise ValueError("Invalid operation")

