from sqlalchemy.exc import SQLAlchemyError

def func(action, data, secret_key, db_url):
    engine = create_engine(db_url)

    if action == 'encrypt':
        key = Fernet.generate_key()
        cipher_suite = Fernet(key)
        encrypted_data = cipher_suite.encrypt(data.encode())
        result = {
            'key': base64.urlsafe_b64encode(key).decode(),
            'encrypted_data': encrypted_data.decode()
        }

    elif action == 'decrypt':
        key = base64.urlsafe_b64decode(data['key'])
        cipher_suite = Fernet(key)
        decrypted_data = cipher_suite.decrypt(data['encrypted_data'].encode()).decode()
        result = {'decrypted_data': decrypted_data}

    elif action == 'store_hmac':
        hmac_value = hmac.new(secret_key.encode(), data.encode(), hashlib.sha256).hexdigest()
        with engine.connect() as connection:
            try:
                connection.execute(text("INSERT INTO hmac_values (hmac) VALUES (:hmac)"), {'hmac': hmac_value})
                result = {'status': 'success', 'hmac': hmac_value}
            except SQLAlchemyError as e:
                result = {'status': 'error', 'message': str(e)}

    elif action == 'retrieve_hmac':
        with engine.connect() as connection:
            try:
                result_set = connection.execute(text("SELECT hmac FROM hmac_values")).fetchall()
                result = {'hmac_values': [row[0] for row in result_set]}
            except SQLAlchemyError as e:
                result = {'status': 'error', 'message': str(e)}

    else:
        result = {'status': 'error', 'message': 'Invalid action'}

    return json.dumps(result)

