import os
import json
import hashlib
import hmac
import sqlite3
from cryptography.fernet import Fernet
from base64 import urlsafe_b64encode, urlsafe_b64decode

DATABASE = 'secure_audit.db'
SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret_key')

def create_database():
    conn = sqlite3.connect(DATABASE)
    cursor = conn.cursor()
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS audits (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            action TEXT NOT NULL,
            timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,
            user_id TEXT NOT NULL
        )
    ''')
    conn.commit()
    conn.close()

def log_audit(action, user_id):
    conn = sqlite3.connect(DATABASE)
    cursor = conn.cursor()
    cursor.execute('INSERT INTO audits (action, user_id) VALUES (?, ?)', (action, user_id))
    conn.commit()
    conn.close()

def encrypt_data(data):
    key = urlsafe_b64encode(hashlib.sha256(SECRET_KEY.encode()).digest())
    fernet = Fernet(key)
    return fernet.encrypt(data.encode())

def decrypt_data(token):
    key = urlsafe_b64encode(hashlib.sha256(SECRET_KEY.encode()).digest())
    fernet = Fernet(key)
    return fernet.decrypt(token).decode()

def verify_signature(data, signature):
    expected_signature = hmac.new(SECRET_KEY.encode(), data.encode(), hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected_signature, signature)

def func(action, user_id, data=None, signature=None):
    create_database()
    if action == 'encrypt':
        if data:
            encrypted_data = encrypt_data(data)
            log_audit(action, user_id)
            return {'status': 'success', 'encrypted_data': encrypted_data.decode()}
    elif action == 'decrypt':
        if data:
            decrypted_data = decrypt_data(data)
            log_audit(action, user_id)
            return {'status': 'success', 'decrypted_data': decrypted_data}
    elif action == 'verify':
        if data and signature:
            is_valid = verify_signature(data, signature)
            log_audit(action, user_id)
            return {'status': 'success', 'is_valid': is_valid}
    return {'status': 'error', 'message': 'Invalid action or parameters'}

