    cursor = db_connection.cursor()

    cursor.execute('''CREATE TABLE IF NOT EXISTS audits (
                        id INTEGER PRIMARY KEY,
                        operation TEXT,
                        user_id TEXT,
                        data BLOB,
                        timestamp DATETIME DEFAULT CURRENT_TIMESTAMP)''')

    if operation == 'encrypt':
        if key is None or not isinstance(data, str):
            return {"error": "Invalid parameters for encryption."}

        cipher = Fernet(key)
        encrypted_data = cipher.encrypt(data.encode())
        cursor.execute("INSERT INTO audits (operation, user_id, data) VALUES (?, ?, ?)", 
                       (operation, user_id, encrypted_data))
        db_connection.commit()
        return {"encrypted_data": encrypted_data.decode()}

    elif operation == 'decrypt':
        if key is None or not isinstance(data, str):
            return {"error": "Invalid parameters for decryption."}

        cursor.execute("SELECT data FROM audits WHERE user_id = ? ORDER BY timestamp DESC LIMIT 1", (user_id,))
        last_entry = cursor.fetchone()
        if last_entry is None:
            return {"error": "No audit record found."}

        cipher = Fernet(key)
        try:
            decrypted_data = cipher.decrypt(last_entry[0]).decode()
            return {"decrypted_data": decrypted_data}
        except Exception:
            return {"error": "Decryption failed."}

    elif operation == 'generate_hmac':
        if key is None or not isinstance(data, str):
            return {"error": "Invalid parameters for HMAC generation."}

        hmac_signature = hmac.new(key.encode(), data.encode(), hashlib.sha256).hexdigest()
        cursor.execute("INSERT INTO audits (operation, user_id, data) VALUES (?, ?, ?)", 
                       (operation, user_id, hmac_signature))
        db_connection.commit()
        return {"hmac": hmac_signature}

    db_connection.close()
    return {"error": "Unknown operation."}

