import os
import hashlib
import hmac
import sqlite3
from cryptography.fernet import Fernet

def func(action, key=None, data=None):
    conn = sqlite3.connect('secure_audit.db')
    cursor = conn.cursor()
    cursor.execute('CREATE TABLE IF NOT EXISTS audits (id INTEGER PRIMARY KEY, action TEXT, result TEXT, timestamp DATETIME DEFAULT CURRENT_TIMESTAMP)')

    secret_key = os.environ.get('SECRET_KEY')
    if not secret_key:
        return {'status': 'error', 'message': 'Secret key not found'}

    if action == 'generate_key':
        key = Fernet.generate_key()
        cursor.execute('INSERT INTO audits (action, result) VALUES (?, ?)', (action, key.decode()))
        conn.commit()
        return {'status': 'success', 'key': key.decode()}

    elif action == 'encrypt':
        if not key or not data:
            return {'status': 'error', 'message': 'Key and data are required for encryption'}
        cipher = Fernet(key)
        encrypted_data = cipher.encrypt(data.encode())
        cursor.execute('INSERT INTO audits (action, result) VALUES (?, ?)', (action, encrypted_data.decode()))
        conn.commit()
        return {'status': 'success', 'encrypted_data': encrypted_data.decode()}

    elif action == 'decrypt':
        if not key or not data:
            return {'status': 'error', 'message': 'Key and data are required for decryption'}
        cipher = Fernet(key)
        try:
            decrypted_data = cipher.decrypt(data.encode())
            cursor.execute('INSERT INTO audits (action, result) VALUES (?, ?)', (action, decrypted_data.decode()))
            conn.commit()
            return {'status': 'success', 'decrypted_data': decrypted_data.decode()}
        except (InvalidToken, Exception):
            return {'status': 'error', 'message': 'Decryption failed'}

    elif action == 'hash':
        if not data:
            return {'status': 'error', 'message': 'Data is required for hashing'}
        hasher = hashlib.sha256()
        hasher.update(data.encode())
        hash_value = hasher.hexdigest()
        cursor.execute('INSERT INTO audits (action, result) VALUES (?, ?)', (action, hash_value))
        conn.commit()
        return {'status': 'success', 'hash': hash_value}

    cursor.close()
    conn.close()
